function sf_ai_script_text($v, string $fallback = 'Not set'): string { $t = trim((string)($v ?? '')); return $t === '' ? $fallback : $t; }
function sf_ai_script_snip($v, int $n = 160, string $fallback = 'Not set'): string { $t = sf_ai_script_text($v, $fallback); return strlen($t) > $n ? rtrim(substr($t, 0, $n - 1)) . '…' : $t; }
function sf_ai_script_first_id(array $rows): int { foreach ($rows as $row) { $id = (int)($row['id'] ?? 0); if ($id > 0) return $id; } return 0; }
function sf_ai_script_find(array $rows, int $id): array { foreach ($rows as $row) if ((int)($row['id'] ?? 0) === $id) return $row; return []; }
function sf_ai_script_card(string $type, string $title, string $detail, array $fields = []): array { return ['type'=>$type,'title'=>$title,'detail'=>$detail,'fields'=>$fields]; }
function sf_ai_script_badge(string $status): string { return sf_admin_status_badge(['draft'=>'draft','ready'=>'active','fix'=>'canceled'][$status] ?? $status); }
function sf_ai_script_has(string $lower, array $terms): bool { foreach ($terms as $term) if ($term !== '' && strpos($lower, strtolower($term)) !== false) return true; return false; }
function sf_ai_script_title(string $prompt, string $fallback = 'AI Draft from Chat'): string { if (preg_match('/\b(?:called|named|titled)\s+([^\.\,\n]{3,90})/i', $prompt, $match)) return trim($match[1]); return $fallback; }
function sf_ai_script_mentions(string $prompt, array $rows, array $keys): array { $out = []; $lower = strtolower($prompt); foreach ($rows as $row) { foreach ($keys as $key) { $name = trim((string)($row[$key] ?? '')); if ($name !== '' && strpos($lower, strtolower($name)) !== false) { $out[] = $name; break; } } if (count($out) >= 8) break; } return array_values(array_unique($out)); }
function sf_ai_script_scene_count(string $prompt): int { $lower = strtolower($prompt); if (preg_match('/\b([0-9]{1,2})\s+(?:scene|scenes|cards|clips)\b/i', $prompt, $match)) return max(1, min(20, (int)$match[1])); foreach (['one'=>1,'two'=>2,'three'=>3,'four'=>4,'five'=>5,'six'=>6,'seven'=>7,'eight'=>8,'nine'=>9,'ten'=>10] as $word => $num) if (preg_match('/\b' . $word . '\s+(?:scene|scenes|cards|clips)\b/', $lower)) return $num; return 0; }
function sf_ai_script_generate(string $prompt, array $ctx): array {
  $prompt = trim($prompt); if ($prompt === '') return [];
  $lower = strtolower($prompt); $title = sf_ai_script_title($prompt); $season = $ctx['season'] ?? []; $episode = $ctx['episode'] ?? []; $scene = $ctx['scene'] ?? [];
  $charNames = sf_ai_script_mentions($prompt, $ctx['characters'] ?? [], ['character_name','name']);
  $bgNames = sf_ai_script_mentions($prompt, $ctx['backgrounds'] ?? [], ['background_name','name','location_label']);
  $assetNames = sf_ai_script_mentions($prompt, $ctx['assets'] ?? [], ['asset_name','name']);
  $tone = []; foreach (['comedy','funny','darker','dark','erotic','romantic','tension','dramatic','reality','scripted','cliffhanger','betrayal','pool','desert','night'] as $hint) if (strpos($lower, $hint) !== false) $tone[] = $hint;
  $cards = []; $sceneCount = sf_ai_script_scene_count($prompt);
  if (sf_ai_script_has($lower, ['season'])) $cards[] = sf_ai_script_card('Draft Create/Update', 'Season draft: ' . $title, 'Prepare a season-level change from the chat prompt.', ['Target'=>'story_seasons','Selected season'=>sf_ai_script_text($season['title'] ?? '', 'New season'),'Fields'=>'title, logline, description, theme_notes, arc_notes, status','Tone hints'=>$tone ? implode(', ', $tone) : 'none','Save'=>'disabled until approval phase']);
  if (sf_ai_script_has($lower, ['episode','epsidoe','ep '])) $cards[] = sf_ai_script_card('Draft Create/Update', 'Episode draft: ' . $title, 'Prepare an episode inside the current season with outline, synopsis, setting, runtime, and characters.', ['Target'=>'story_episodes','Season'=>sf_ai_script_text($season['title'] ?? '', 'Select a season'),'Characters'=>$charNames ? implode(', ', $charNames) : 'none detected','Fields'=>'title, logline, synopsis, runtime_target_minutes, setting_label, episode_outline','Save'=>'disabled until approval phase']);
  if ($sceneCount > 1) $cards[] = sf_ai_script_card('Draft Batch', 'Batch scene-card draft: ' . $sceneCount . ' scenes', 'Prepare multiple scene cards for the selected episode.', ['Target'=>'storyboards / scene cards','Episode'=>sf_ai_script_text($episode['title'] ?? '', 'Select an episode'),'Scene count'=>$sceneCount,'Characters'=>$charNames ? implode(', ', $charNames) : 'use episode cast','Tone hints'=>$tone ? implode(', ', $tone) : 'none','Save'=>'disabled until approval phase']);
  elseif (sf_ai_script_has($lower, ['scene','card','dialogue','beat','cliffhanger','clip','microdrama','rewrite','update this'])) $cards[] = sf_ai_script_card('Draft Create/Update', 'Scene card draft', 'Prepare a new scene card or update the selected scene with beats, dialogue direction, conflict, emotional turn, cliffhanger, and continuity.', ['Target'=>'storyboards / scene cards','Episode'=>sf_ai_script_text($episode['title'] ?? '', 'Select an episode'),'Selected scene'=>sf_ai_script_text($scene['title'] ?? '', 'New scene'),'Characters'=>$charNames ? implode(', ', $charNames) : 'none detected','Backgrounds'=>$bgNames ? implode(', ', $bgNames) : 'none detected','Assets'=>$assetNames ? implode(', ', $assetNames) : 'none detected','Save'=>'disabled until approval phase']);
  if (sf_ai_script_has($lower, ['character','cast','actor','performer']) || (sf_ai_script_has($lower, ['create','add','new']) && sf_ai_script_has($lower, ['named','called']))) $cards[] = sf_ai_script_card('Draft Create/Update', 'Character profile draft: ' . $title, 'Prepare a reusable character profile with bio, motivation, personality, relationships, and arc.', ['Target'=>'story_characters','Suggested name'=>$title,'Existing mentions'=>$charNames ? implode(', ', $charNames) : 'none','Fields'=>'character_name, role_type, short_bio, motivation, personality_notes, relationship_notes, season_arc','Save'=>'disabled until approval phase']);
  if (sf_ai_script_has($lower, ['background','location','pool','desert','stage','room','house','bar','backstage','interior','exterior','night','day'])) $cards[] = sf_ai_script_card('Draft Create/Assign', 'Background draft', 'Prepare a reusable scene background or assign an existing background.', ['Target'=>'story_scene_backgrounds','Detected backgrounds'=>$bgNames ? implode(', ', $bgNames) : 'none','Location hint'=>$title,'Fields'=>'background_name, background_type, location_label, time_of_day, short_description, continuity_notes','Save'=>'disabled until approval phase']);
  if (sf_ai_script_has($lower, ['asset','prop','vehicle','truck','car','guitar','wardrobe','necklace','chain','document','item'])) $cards[] = sf_ai_script_card('Draft Create/Assign', 'Series asset draft', 'Prepare a recurring prop, vehicle, wardrobe piece, document, or continuity item.', ['Target'=>'story_series_assets','Detected assets'=>$assetNames ? implode(', ', $assetNames) : 'none','Detected characters'=>$charNames ? implode(', ', $charNames) : 'none','Fields'=>'asset_name, asset_type, short_description, continuity_notes, image_path','Save'=>'disabled until approval phase']);
  if ($charNames || sf_ai_script_has($lower, ['assign','add','include','put'])) $cards[] = sf_ai_script_card('Draft Assignment', 'Continuity assignment draft', 'Prepare character/background/asset assignments for the active season, episode, or scene.', ['Characters'=>$charNames ? implode(', ', $charNames) : 'none detected','Backgrounds'=>$bgNames ? implode(', ', $bgNames) : 'none detected','Assets'=>$assetNames ? implode(', ', $assetNames) : 'none detected','Target context'=>sf_ai_script_text($episode['title'] ?? '', 'No episode') . ' / ' . sf_ai_script_text($scene['title'] ?? '', 'New scene'),'Save'=>'disabled until approval phase']);
  if (!$cards) $cards[] = sf_ai_script_card('Draft Direction', 'Script direction draft', 'The prompt was captured as creative direction. Phase 3 can route it into a saved record after approval.', ['Prompt'=>sf_ai_script_snip($prompt, 140),'Target context'=>sf_ai_script_text($episode['title'] ?? '', 'No episode'),'Next step'=>'Clarify create/update target','Save'=>'disabled until approval phase']);
  return $cards;
}
$request = ($_SERVER['REQUEST_METHOD'] ?? 'GET') === 'POST' ? $_POST : $_GET;
$seasons = function_exists('sf_story_v1_seasons') ? sf_story_v1_seasons() : []; $allEpisodes = function_exists('sf_story_v1_episodes') ? sf_story_v1_episodes() : [];
$seasonId = sf_admin_int($request['season_id'] ?? null, 0) ?? 0; if ($seasonId <= 0) $seasonId = (int)($allEpisodes[0]['story_season_id'] ?? sf_ai_script_first_id($seasons)); $selectedSeason = sf_ai_script_find($seasons, $seasonId) ?: ($seasons[0] ?? []); $seasonId = (int)($selectedSeason['id'] ?? $seasonId);
$episodes = $seasonId > 0 && function_exists('sf_story_v1_episodes') ? sf_story_v1_episodes($seasonId) : $allEpisodes; $episodeId = sf_admin_int($request['episode_id'] ?? null, 0) ?? 0; if ($episodeId <= 0 || !sf_ai_script_find($episodes, $episodeId)) $episodeId = sf_ai_script_first_id($episodes ?: $allEpisodes); $selectedEpisode = sf_ai_script_find($episodes, $episodeId) ?: sf_ai_script_find($allEpisodes, $episodeId) ?: ($episodes[0] ?? []); $episodeId = (int)($selectedEpisode['id'] ?? $episodeId);
$scenes = $episodeId > 0 && function_exists('sf_story_v1_episode_storyboards') ? sf_story_v1_episode_storyboards($episodeId) : []; $sceneId = sf_admin_int($request['scene_id'] ?? null, 0) ?? 0; if ($sceneId <= 0 || !sf_ai_script_find($scenes, $sceneId)) $sceneId = sf_ai_script_first_id($scenes); $selectedScene = sf_ai_script_find($scenes, $sceneId) ?: ($scenes[0] ?? []);
$characters = function_exists('sf_story_v1_characters') ? sf_story_v1_characters('active') : []; $backgrounds = function_exists('sf_scene_backgrounds_all') ? sf_scene_backgrounds_all() : []; $activeBackgrounds = array_values(array_filter($backgrounds, static fn($r) => (string)($r['status'] ?? 'active') === 'active')); $assets = function_exists('sf_series_assets_all') ? sf_series_assets_all() : []; $activeAssets = array_values(array_filter($assets, static fn($r) => (string)($r['status'] ?? 'active') === 'active')); $providerOptions = function_exists('sf_ai_provider_options') ? sf_ai_provider_options() : ['chatgpt'=>'ChatGPT / OpenAI','claude'=>'Claude / Anthropic'];
$prompt = trim((string)($request['script_prompt'] ?? '')); $generatedActions = $prompt !== '' ? sf_ai_script_generate($prompt, ['season'=>$selectedSeason,'episode'=>$selectedEpisode,'scene'=>$selectedScene,'characters'=>$characters,'backgrounds'=>$activeBackgrounds,'assets'=>$activeAssets]) : [];
$draftActions = $generatedActions ?: [sf_ai_script_card('Create','Create a new season','Draft a season container with title, logline, theme notes, arc notes, status, and sort order.',['Target'=>'story_seasons','Approval'=>'Required before save']),sf_ai_script_card('Create','Create a new episode','Draft an episode inside the selected season with logline, synopsis, runtime, setting, outline, and character assignments.',['Season'=>sf_ai_script_text($selectedSeason['title'] ?? '', 'Select a season'),'Target'=>'story_episodes']),sf_ai_script_card('Create / Update','Create or update a scene card','Draft a new scene or update the selected scene with beats, dialogue, conflict, cliffhanger, characters, background, assets, and continuity notes.',['Episode'=>sf_ai_script_text($selectedEpisode['title'] ?? '', 'Select an episode'),'Scene'=>sf_ai_script_text($selectedScene['title'] ?? '', 'New scene')]),sf_ai_script_card('Create','Create a character','Draft a reusable character profile with bio, motivation, personality, relationships, season arc, image path, and assets.',['Target'=>'story_characters','Approval'=>'Required before save']),sf_ai_script_card('Create','Create background or asset','Draft reusable scene backgrounds, props, vehicles, wardrobe, instruments, or other continuity assets.',['Backgrounds'=>count($activeBackgrounds),'Assets'=>count($activeAssets)]),sf_ai_script_card('Assign','Assign story continuity','Prepare character, background, and asset assignments for an episode or scene without applying them until approved.',['Characters'=>count($characters),'Mode'=>'Draft only'])];
$examplePrompts = ['Create a new episode in this season where Rio lies about the record deal and Jax finds out at the pool.','Update this scene card so it happens at night, add Mia and Angel, and end with a cliffhanger text message.','Create a new character named Luna. She is funny, dangerous, and knows everyone’s secrets.','Make five 30-second microdrama scene cards for this episode with stronger comedy and more tension.','Create a background called Desert Pool House at Night and assign it to every pool scene.'];
require __DIR__ . '/../includes/header.php'; sf_admin_shell_start('AI Script Producer','AI Script Producer','Chat-first control for seasons, episodes, scenes, characters, backgrounds, and story assets.','ai-script-assistant');
