fields{display:flex;flex-wrap:wrap;gap:6px;margin-top:12px}.ai-script-producer-page .sf-script-fields small,.ai-script-producer-page .sf-script-prompt-meta small{border:1px solid rgba(232,198,127,.18);border-radius:999px;padding:4px 8px;color:#f5d98d;font-size:11px;font-weight:900}.ai-script-producer-page .sf-script-capability-list{display:grid;gap:10px}.ai-script-producer-page .sf-script-capability-list div{padding:12px;border:1px solid rgba(255,255,255,.08);border-radius:14px;background:rgba(0,0,0,.13)}.ai-script-producer-page .sf-script-capability-list strong{color:#fff}.ai-script-producer-page .sf-script-capability-list small{display:block;margin-top:4px;color:rgba(255,255,255,.58);line-height:1.45}@media(max-width:1180px){.ai-script-producer-page .sf-script-layout,.ai-script-producer-page .sf-script-hero{grid-template-columns:1fr}.ai-script-producer-page .sf-script-card-grid,.ai-script-producer-page .sf-script-stats{grid-template-columns:repeat(2,minmax(0,1fr))}}@media(max-width:720px){.ai-script-producer-page .sf-script-context-grid,.ai-script-producer-page .sf-script-card-grid,.ai-script-producer-page .sf-script-stats{grid-template-columns:1fr}}</style>
