<section class='sf-script-layout'><div class='sf-script-panel'><span class='sf-panel-eyebrow'>Chat Window</span><div class='sf-script-chat'><div class='sf-script-msg'><span>Assistant</span><strong>I’m ready to turn chat into draft action cards.</strong><p class='sf-script-copy'>Selected context: <?= sf_admin_h(sf_ai_script_text($selectedSeason['title'] ?? '', 'No season')) ?> → <?= sf_admin_h(sf_ai_script_text($selectedEpisode['title'] ?? '', 'No episode')) ?> → <?= sf_admin_h(sf_ai_script_text($selectedScene['title'] ?? '', 'New scene')) ?>.</p></div><?php if ($prompt !== ''): ?><div class='sf-script-msg'><span>You</span><strong><?= sf_admin_h(sf_ai_script_snip($prompt, 180)) ?></strong><p class='sf-script-copy'>Generated <?= count($generatedActions) ?> draft action card(s). Review below. Nothing has been saved.</p><div class='sf-script-prompt-meta'><small>Phase 2 parser</small><small>No database writes</small><small>Approval required later</small></div></div><?php else: ?><div class='sf-script-msg'><span>System</span><strong>Phase 2 is draft-card generation.</strong><p class='sf-script-copy'>Submit a prompt to generate structured action cards. Save/execute remains disabled until the approval and audit layer is built.</p></div><?php endif; ?><form class='sf-admin-form' method='post'><?= sf_csrf_field() ?><input type='hidden' name='season_id' value='<?= (int)$seasonId ?>'><input type='hidden' name='episode_id' value='<?= (int)$episodeId ?>'><input type='hidden' name='scene_id' value='<?= (int)$sceneId ?>'><label>Ask the AI Script Producer<textarea name='script_prompt' placeholder='Example: Create a new scene where Rio and Mia argue by the pool at night, assign the Desert Pool House background, add Jax watching from the balcony, and end with a cliffhanger text message.'><?= sf_admin_h($prompt) ?></textarea></label><div class='sf-admin-form-actions'><button type='submit'>Generate Draft Actions</button><button type='button' disabled>Save Approved Changes — Phase 3</button></div></form></div></div><aside class='sf-script-panel'><span class='sf-panel-eyebrow'>Current Story Context</span><h3><?= sf_admin_h(sf_ai_script_text($selectedEpisode['title'] ?? '', 'No episode selected')) ?></h3><p class='sf-script-copy'><strong>Season:</strong> <?= sf_admin_h(sf_ai_script_text($selectedSeason['title'] ?? '')) ?><br><strong>Episode:</strong> <?= sf_admin_h(sf_ai_script_text($selectedEpisode['title'] ?? '')) ?><br><strong>Scene:</strong> <?= sf_admin_h(sf_ai_script_text($selectedScene['title'] ?? '', 'New scene')) ?></p><p class='sf-script-copy'><strong>Episode outline:</strong><br><?= sf_admin_h(sf_ai_script_snip($selectedEpisode['episode_outline'] ?? $selectedEpisode['synopsis'] ?? $selectedEpisode['logline'] ?? '', 260, 'Episode outline pending.')) ?></p><p class='sf-script-copy'><strong>Model options:</strong><br><?= sf_admin_h(implode(', ', array_values($providerOptions))) ?></p></aside></section>
